1	#!/usr/bin/env node
2	/**
3	 * Stand up a disposable prod test user and print its session JSON.
4	 *
5	 *   node provision.mjs <label>            # register + pod + env + wait ready
6	 *   node provision.mjs <label> --reuse    # reuse the cached user for <label> if it exists
7	 *
8	 * Writes `.state/users/<label>.json` (gitignored) so a scenario can be re-run against the same
9	 * user, and so a subagent that hits a budget wall can just provision a new one and carry on.
10	 */
11	import { mkdirSync, readFileSync, writeFileSync, existsSync } from 'node:fs';
12	import {
13	  provisionUser,
14	  budget,
15	  podBase,
16	  agentEnvFromSdk,
17	  mergePodEnv,
