149	  for (const [k, v] of Object.entries(vars)) map.set(k, v);
150	  const content = [...map].map(([k, v]) => `${k}=${v}`).join('\n') + '\n';
151	  await pod.req('PUT', '/api/env', { content });
152	  return content;
153	}
