1	/**
2	 * lmthing.cloud gateway client — everything a scenario needs to stand up a disposable prod
3	 * test user: register, provision the compute pod, load API keys into pod env, wake it.
4	 *
5	 * Budget note: scenarios burn real tokens. We deliberately load the **direct Azure** keys from
6	 * `sdk/org/.env` into the pod env (AZURE_API_KEY + AZURE_RESOURCE_NAME + the LM_MODEL_* aliases),
7	 * so agent traffic goes straight to Azure AI Foundry and never touches the per-user LiteLLM key
8	 * that carries the tier budget. A user therefore does not "run out" mid-scenario. `budget()` is
9	 * still exposed so a scenario can assert on spend, and `provisionUser()` is cheap enough to call
10	 * again if a pod ever does get budget-capped.
11	 */
12	import { readFileSync } from 'node:fs';
13	import { SDK_ORG } from './paths.mjs';
14	import { mintSession } from './jwt.mjs';
15	import { fetchResilient } from './pod.mjs';
16	
17	export const GATEWAY = process.env.LM_GATEWAY ?? 'https://lmthing.cloud';
18	
19	class HttpError extends Error {
20	  constructor(method, url, status, body) {
21	    super(`${method} ${url} → ${status}: ${typeof body === 'string' ? body : JSON.stringify(body)}`);
22	    this.status = status;
23	    this.body = body;
24	  }
25	}
26	
27	async function req(method, path, { token, body, base = GATEWAY } = {}) {
28	  const res = await fetchResilient(`${base}${path}`, {
29	    method,
30	    headers: {
31	      ...(body ? { 'content-type': 'application/json' } : {}),
32	      ...(token ? { authorization: `Bearer ${token}` } : {}),
33	    },
34	    ...(body ? { body: JSON.stringify(body) } : {}),
35	  });
36	  const text = await res.text();
37	  let parsed = text;
38	  try {
39	    parsed = JSON.parse(text);
40	  } catch {
41	    /* keep raw text */
42	  }
43	  if (!res.ok) throw new HttpError(method, path, res.status, parsed);
44	  return parsed;
45	}
46	
47	/** Parse `sdk/org/.env` into a plain object (no dotenv dep; ignores comments + blanks). */
48	export function readSdkEnv() {
49	  const raw = readFileSync(`${SDK_ORG}/.env`, 'utf8');
50	  const out = {};
51	  for (const line of raw.split('\n')) {
52	    const m = /^\s*([A-Z0-9_]+)\s*=\s*(.*)\s*$/.exec(line);
53	    if (!m) continue; // comment or blank
54	    out[m[1]] = m[2].replace(/^["']|["']$/g, '');
55	  }
56	  return out;
57	}
58	
59	/**
60	 * The env vars a pod needs to run agents against Azure directly (budget-free), plus web search.
61	 * Anything absent from sdk/org/.env is simply omitted.
62	 */
63	export function agentEnvFromSdk() {
64	  const env = readSdkEnv();
65	  const keys = [
66	    'AZURE_API_KEY',
67	    'AZURE_RESOURCE_NAME',
68	    'TAVILY_API_KEY',
69	    'LM_MODEL_XS',
70	    'LM_MODEL_S',
71	    'LM_MODEL_M',
72	    'LM_MODEL_L',
73	    'LM_MODEL_M_R',
74	    'LM_MODEL_L_R',
75	    'LM_MODEL_VISION',
76	    'LM_TRANSCRIBE_MODEL',
77	  ];
78	  const out = {};
79	  for (const k of keys) if (env[k]) out[k] = env[k];
80	  return out;
81	}
82	
83	/** `POST /api/auth/register` → { user_id, api_key }. Login is broken in prod; we mint instead. */
84	export async function register(email, password) {
85	  return req('POST', '/api/auth/register', { body: { email, password } });
86	}
87	
88	export const ensurePod = (token) => req('POST', '/api/compute/ensure', { token });
89	export const podStatus = (token) => req('GET', '/api/compute/status', { token });
90	export const wakePod = (token) => req('POST', '/api/compute/wake', { token });
91	
92	/**
93	 * Remaining LiteLLM budget. NOTE this lives on the POD (`routes/budget.ts` relays the caller's
94	 * Authorization to the gateway and computes the line with the master key) — there is no
95	 * `/api/budget` on the gateway itself. Scenarios run on direct Azure keys, so this is
96	 * informational: it tells you whether the tier key is exhausted, not whether the run can proceed.
97	 */
98	export const budget = (token) => req('GET', '/api/budget', { token, base: podBase() });
99	
100	/**
101	 * `PUT /api/compute/env` REPLACES the whole var set, so always GET-merge-PUT — clobbering the
102	 * gateway-injected lmthingcloud creds would break the pod.
103	 *
104	 * A PUT rolls the deployment, and pod sessions are IN-MEMORY: any session created against the
105	 * old pod dies with it (`GET /api/sessions/:id/events` → 404 unknown session). So we skip the
106	 * write entirely when nothing would change — which is the common case on a reused test user.
107	 *
108	 * @returns {{merged: object, changed: boolean}}
109	 */
110	export async function mergePodEnv(token, vars) {
111	  const current = await req('GET', '/api/compute/env', { token }).catch(() => ({ vars: {} }));
112	  const existing = current.vars ?? {};
113	  const merged = { ...existing, ...vars };
114	  const changed = Object.entries(merged).some(([k, v]) => existing[k] !== v);
115	  if (!changed) return { merged, changed: false };
116	  await req('PUT', '/api/compute/env', { token, body: { vars: merged } });
117	  return { merged, changed: true };
118	}
119	
120	/**
121	 * Wait until a session created NOW would survive — i.e. the env-triggered rollout is finished.
122	 *
123	 * There is no reliable "which pod process am I talking to" signal from outside, and the gateway's
124	 * `pod.ready` (readyReplicas > 0) stays true across a rolling update because the OLD replica is
125	 * still ready. So we test the property we actually need, directly: create a probe session, wait,
126	 * and confirm it still exists. If the pod rolled under us, the probe vanishes and we retry.
127	 */
128	export async function waitPodSettled(token, base = podBase(), { attempts = 6, settleMs = 9_000 } = {}) {
129	  const headers = { authorization: `Bearer ${token}`, 'content-type': 'application/json' };
130	  for (let i = 0; i < attempts; i++) {
131	    try {
132	      const res = await fetch(`${base}/api/sessions`, {
133	        method: 'POST',
134	        headers,
135	        body: JSON.stringify({ projectId: 'user' }),
136	      });
137	      if (res.ok) {
138	        const { sessionId } = await res.json();
139	        await new Promise((r) => setTimeout(r, settleMs));
140	        const list = await fetch(`${base}/api/sessions`, { headers }).then((r) => r.json());
141	        const alive = (list.sessions ?? []).some((s) => s.sessionId === sessionId);
142	        if (alive) {
143	          // Clean up the probe so it doesn't pollute the scenario's session list.
144	          await fetch(`${base}/api/sessions/${sessionId}`, { method: 'DELETE', headers }).catch(() => {});
145	          return true;
146	        }
147	      }
148	    } catch {
149	      /* pod mid-roll — retry */
150	    }
151	    await new Promise((r) => setTimeout(r, 5_000));
152	  }
153	  throw new Error('pod never settled: a freshly created session keeps disappearing');
154	}
155	
156	/**
157	 * Poll until the gateway reports the pod ready (or throw).
158	 *
159	 * Readiness lives at `status.pod.ready` / `status.pod.stage === 'ready'` — NOT at the top level.
160	 * Note "ready" here means readyReplicas>0, which precedes Envoy actually wiring the woken
161	 * endpoint (see the pod-readiness-edge race); callers that immediately hit the pod should
162	 * tolerate one early 503, which `Pod.req` surfaces as a normal HttpError.
163	 */
164	export async function waitPodReady(token, { timeoutMs = 180_000, intervalMs = 3_000 } = {}) {
165	  const deadline = Date.now() + timeoutMs;
166	  let last;
167	  while (Date.now() < deadline) {
168	    try {
169	      last = await podStatus(token);
170	      if (last?.pod?.ready || last?.pod?.stage === 'ready') return last;
171	    } catch (err) {
172	      last = { error: String(err) };
173	    }
174	    await new Promise((r) => setTimeout(r, intervalMs));
175	  }
176	  throw new Error(`pod not ready after ${timeoutMs}ms: ${JSON.stringify(last)}`);
177	}
178	
179	/**
180	 * Full disposable-test-user provision: register → mint session → ensure pod → load agent keys →
181	 * wait ready. Returns everything a scenario needs, including a `pod` base URL.
182	 *
183	 * Pods are reached through the chat origin: Envoy validates the JWT and routes on the `sub` claim
184	 * to `lmthing.user-<id>.svc`, waking a scaled-to-zero pod on the way.
185	 */
186	export async function provisionUser({ label = 'scn', password = 'Test-Passw0rd!' } = {}) {
187	  const email = `${label}-${Date.now().toString(36)}@lmthing.test`;
188	  const { user_id: userId } = await register(email, password);
189	  const session = mintSession(userId, email);
190	  await ensurePod(session.accessToken);
191	  // Pod env must be loaded BEFORE the first agent turn: the PUT rolls the pod, and a restart
192	  // mid-scenario destroys in-memory sessions (it would look like a spurious failure).
193	  const { changed } = await mergePodEnv(session.accessToken, agentEnvFromSdk());
194	  await waitPodReady(session.accessToken);
195	  if (changed) await waitPodSettled(session.accessToken);
196	  return { email, password, userId, session, token: session.accessToken, pod: podBase() };
197	}
198	
199	/** The origin that fronts a user's pod (Envoy routes by JWT `sub`). */
200	export const podBase = () => process.env.LM_POD_BASE ?? 'https://lmthing.chat';
